import os
import hashlib
import hmac
import secrets
import time
from functools import wraps
from datetime import datetime, timedelta
from flask import Flask, request, session, jsonify, redirect, url_for

app = Flask(__name__)
app.secret_key = os.environ.get('SECRET_KEY', secrets.token_hex(32))
app.config['PERMANENT_SESSION_LIFETIME'] = timedelta(days=7)

users_db = {}
sessions_db = {}
login_attempts = {}

RATE_LIMIT_ATTEMPTS = 5
RATE_LIMIT_WINDOW = 300


def hash_password(password, salt=None):
    if salt is None:
        salt = secrets.token_hex(16)
    pwd_hash = hashlib.pbkdf2_hmac('sha256', password.encode('utf-8'), salt.encode('utf-8'), 100000)
    return f"{salt}${pwd_hash.hex()}"


def verify_password(password, hashed_password):
    try:
        salt, pwd_hash = hashed_password.split('$')
        new_hash = hashlib.pbkdf2_hmac('sha256', password.encode('utf-8'), salt.encode('utf-8'), 100000)
        return hmac.compare_digest(new_hash.hex(), pwd_hash)
    except:
        return False


def generate_session_token():
    return secrets.token_urlsafe(32)


def check_rate_limit(identifier):
    current_time = time.time()
    if identifier not in login_attempts:
        login_attempts[identifier] = []
    
    login_attempts[identifier] = [
        attempt_time for attempt_time in login_attempts[identifier]
        if current_time - attempt_time < RATE_LIMIT_WINDOW
    ]
    
    if len(login_attempts[identifier]) >= RATE_LIMIT_ATTEMPTS:
        return False
    
    login_attempts[identifier].append(current_time)
    return True


def login_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        session_token = session.get('session_token')
        if not session_token or session_token not in sessions_db:
            return jsonify({'error': 'Authentication required'}), 401
        
        session_data = sessions_db[session_token]
        if datetime.now() > session_data['expires']:
            del sessions_db[session_token]
            session.pop('session_token', None)
            return jsonify({'error': 'Session expired'}), 401
        
        return f(*args, **kwargs)
    return decorated_function


@app.route('/register', methods=['POST'])
def register():
    data = request.get_json()
    username = data.get('username')
    password = data.get('password')
    
    if not username or not password:
        return jsonify({'error': 'Username and password required'}), 400
    
    if len(password) < 8:
        return jsonify({'error': 'Password must be at least 8 characters'}), 400
    
    if username in users_db:
        return jsonify({'error': 'Username already exists'}), 400
    
    users_db[username] = {
        'password': hash_password(password),
        'created_at': datetime.now().isoformat()
    }
    
    return jsonify({'message': 'User registered successfully'}), 201


@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    username = data.get('username')
    password = data.get('password')
    
    if not username or not password:
        return jsonify({'error': 'Username and password required'}), 400
    
    client_ip = request.remote_addr
    if not check_rate_limit(client_ip):
        return jsonify({'error': 'Too many login attempts. Try again later'}), 429
    
    if username not in users_db:
        return jsonify({'error': 'Invalid credentials'}), 401
    
    if not verify_password(password, users_db[username]['password']):
        return jsonify({'error': 'Invalid credentials'}), 401
    
    session_token = generate_session_token()
    session['session_token'] = session_token
    session.permanent = True
    
    sessions_db[session_token] = {
        'username': username,
        'created_at': datetime.now(),
        'expires': datetime.now() + timedelta(days=7),
        'ip': client_ip
    }
    
    if client_ip in login_attempts:
        login_attempts[client_ip] = []
    
    return jsonify({
        'message': 'Login successful',
        'session_token': session_token
    }), 200


@app.route('/logout', methods=['POST'])
@login_required
def logout():
    session_token = session.get('session_token')
    if session_token in sessions_db:
        del sessions_db[session_token]
    session.pop('session_token', None)
    return jsonify({'message': 'Logged out successfully'}), 200


@app.route('/profile', methods=['GET'])
@login_required
def profile():
    session_token = session.get('session_token')
    session_data = sessions_db[session_token]
    username = session_data['username']
    
    return jsonify({
        'username': username,
        'created_at': users_db[username]['created_at'],
        'session_created': session_data['created_at'].isoformat()
    }), 200


@app.route('/change_password', methods=['POST'])
@login_required
def change_password():
    data = request.get_json()
    old_password = data.get('old_password')
    new_password = data.get('new_password')
    
    if not old_password or not new_password:
        return jsonify({'error': 'Old and new password required'}), 400
    
    if len(new_password) < 8:
        return jsonify({'error': 'New password must be at least 8 characters'}), 400
    
    session_token = session.get('session_token')
    username = sessions_db[session_token]['username']
    
    if not verify_password(old_password, users_db[username]['password']):
        return jsonify({'error': 'Invalid old password'}), 401
    
    users_db[username]['password'] = hash_password(new_password)
    
    return jsonify({'message': 'Password changed successfully'}), 200


@app.route('/sessions', methods=['GET'])
@login_required
def list_sessions():
    session_token = session.get('session_token')
    username = sessions_db[session_token]['username']
    
    user_sessions = []
    for token, data in sessions_db.items():
        if data['username'] == username:
            user_sessions.append({
                'token': token[:8] + '...',
                'created_at': data['created_at'].isoformat(),
                'expires': data['expires'].isoformat(),
                'ip': data['ip'],
                'current': token == session_token
            })
    
    return jsonify({'sessions': user_sessions}), 200


@app.route('/revoke_session/<session_id>', methods=['POST'])
@login_required
def revoke_session(session_id):
    current_token = session.get('session_token')
    username = sessions_db[current_token]['username']
    
    if session_id in sessions_db and sessions_db[session_id]['username'] == username:
        del sessions_db[session_id]
        return jsonify({'message': 'Session revoked successfully'}), 200
    
    return jsonify({'error': 'Session not found'}), 404


